import { useSearchParams } from "react-router-dom";
import products from "../data/products";
import ProductCard from "../components/ProductCard";

function Home() {
  const [searchParams] = useSearchParams();
  const query = (searchParams.get("q") || "").toLowerCase();

  const filteredProducts = products.filter((p) =>
    p.name.toLowerCase().includes(query)
  );

  const totalProducts = products.length;
  const totalStores = 3;
  const averageRating = (
    products.reduce((sum, p) => sum + p.rating, 0) / products.length
  ).toFixed(1);

  const bestDeals = products.filter((p) => {
    const prices = p.stores.map((s) => s.price);
    return Math.max(...prices) - Math.min(...prices) > 1000;
  }).length;

  return (
    <div>
      <div className="heroSection">
        <h1>Compare Prices Smartly</h1>
        <p>
          Find the best deal across Amazon, Flipkart, and Croma with ratings,
          trust indicators, and smart product comparison.
        </p>
      </div>

      <div className="dashboardSection">
        <div className="dashboardCard">
          <h3>{totalProducts}</h3>
          <p>Total Products</p>
        </div>

        <div className="dashboardCard">
          <h3>{totalStores}</h3>
          <p>Store Platforms</p>
        </div>

        <div className="dashboardCard">
          <h3>{averageRating} ⭐</h3>
          <p>Average Rating</p>
        </div>

        <div className="dashboardCard">
          <h3>{bestDeals}</h3>
          <p>Top Savings Deals</p>
        </div>
      </div>

      <div className="sectionHeader">
        <h2>{query ? `Search Results for "${query}"` : "Top Products"}</h2>
        <span>{filteredProducts.length} products</span>
      </div>

      <div className="grid">
        {filteredProducts.length > 0 ? (
          filteredProducts.map((p, i) => <ProductCard product={p} key={i} />)
        ) : (
          <div className="emptyState">
            <h3>No products found</h3>
            <p>Try searching for iPhone, Samsung, MacBook, iPad, Canon, etc.</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default Home;
